INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('1', 'Bienvenido al Blog', 'General', '# Bienvenido\n\nEste es un blog de tutoriales sobre programación, Linux y seguridad.', NULL, NULL, '1', '5', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('2', 'Introducción a Linux', 'Linux', '# Introducción a Linux\n\nLinux es un sistema operativo de código abierto.\n\n## Distribuciones\n- Ubuntu\n- Debian\n\n```bash\nls -la\ncd /home\n```', NULL, NULL, '1', '3', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('3', 'Tutorial de Python', 'Programación', '# Tutorial de Python\n\n```python\nnombre = \"Juan\"\nedad = 25\n```', NULL, NULL, '2', '0', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('4', 'Configurar SSH', 'Linux', '# Configurar SSH\r\n\r\n```bash\r\nsudo apt update\r\nsudo apt install openssh-server\r\nsudo systemctl start ssh\r\nsudo systemctl enable ssh\r\n```\r\n\r\n## Conectar\r\n```bash\r\nssh usuario@servidor\r\n```', NULL, 'https://www.youtube.com/watch?v=c0HtiBbVsFQ', '1', '11', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('5', 'Comandos Servidor', 'Linux', '# Comandos básicos servidor\n\n## Archivos\n```bash\nls -la\ncd /home\nmkdir carpeta\nrm archivo\ncp origen destino\nmv origen destino\n```\n\n## Paquetes\n```bash\nsudo apt update\nsudo apt upgrade\nsudo apt install nombre\n```\n\n## Servicios\n```bash\nsudo systemctl status nginx\nsudo systemctl start nginx\nsudo systemctl stop nginx\nsudo systemctl restart nginx\n```\n\n## Usuarios\n```bash\nsudo adduser nombre\nsudo usermod -aG sudo nombre\n```', NULL, NULL, '1', '1', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('6', 'LAMP Debian/Ubuntu', 'Linux', '# LAMP Server\n\nLAMP = Linux + Apache + MySQL + PHP\n\n```bash\n# Apache\nsudo apt install apache2 -y\n\n# MySQL\nsudo apt install mariadb-server -y\nsudo mysql_secure_installation\n\n# PHP\nsudo apt install php libapache2-mod-php php-mysql -y\n\n# Verificar\necho \"<?php phpinfo(); ?>\" | sudo tee /var/www/html/info.php\n```', NULL, NULL, '1', '1', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('7', 'Firewall UFW', 'Linux', '# Firewall UFW\n\n```bash\n# Instalar\nsudo apt install ufw\n\n# Reglas\nsudo ufw allow ssh\nsudo ufw allow 80/tcp\nsudo ufw allow 443/tcp\n\n# Habilitar\nsudo ufw enable\n\n# Ver estado\nsudo ufw status\n```\n\n## Otras reglas\n```bash\nsudo ufw allow 22/tcp\nsudo ufw allow 3306/tcp  # MySQL\nsudo ufw allow 8080/tcp\n```', NULL, NULL, '1', '0', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('8', 'Servidor NFS', 'Linux', '# Servidor NFS\n\nNFS permite compartir archivos entre servidores.\n\n## Servidor\n```bash\nsudo apt install nfs-kernel-server\nsudo mkdir -p /var/nfs/compartido\nsudo chmod 777 /var/nfs/compartido\n\n# Editar /etc/exports\n/var/nfs/compartido 192.168.1.0/24(rw,sync,no_subtree_check)\n\nsudo exportfs -a\nsudo systemctl restart nfs-kernel-server\n```\n\n## Cliente\n```bash\nsudo apt install nfs-common\nsudo mkdir -p /mnt/nfs\nsudo mount 192.168.1.100:/var/nfs/compartido /mnt/nfs\n```', NULL, NULL, '1', '1', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('9', 'Nginx Reverse Proxy', 'Linux', '# Nginx como Proxy Inverso\n\n```bash\nsudo apt install nginx\n```\n\n## Configurar\n```nginx\nserver {\n    listen 80;\n    server_name mi-dominio.com;\n    \n    location / {\n        proxy_pass http://127.0.0.1:3000;\n        proxy_set_header Host $host;\n        proxy_set_header X-Real-IP $remote_addr;\n        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n    }\n}\n```\n\n## Activar\n```bash\nsudo ln -s /etc/nginx/sites-available/mi-dominio /etc/nginx/sites-enabled/\nsudo nginx -t\nsudo systemctl reload nginx\n```', NULL, NULL, '1', '0', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('10', 'Usuario Sudo', 'Linux', '# Crear Usuario Sudo\n\n```bash\n# Crear usuario\nsudo adduser nombre_usuario\n\n# Agregar a grupo sudo\nsudo usermod -aG sudo nombre_usuario\n\n# Verificar\nsu - nombre_usuario\nsudo whoami\n# Debe mostrar: root\n```\n\n## Editar sudoers\n```bash\nsudo visudo\n# Agregar:\nnombre_usuario ALL=(ALL:ALL) ALL\n```', NULL, NULL, '1', '1', '2026-04-01 15:07:39');
INSERT INTO `posts` (`id`, `title`, `category`, `content`, `image`, `video`, `author_id`, `views`, `created_at`) VALUES ('11', 'Redes Sociales', 'General', '*Las redes sociales son plataformas digitales que facilitan la comunicación, interacción y creación de comunidades en tiempo real. Permiten compartir información, fotos y videos, actuando como canales estratégicos para usuarios y empresas. Las más populares incluyen Facebook, YouTube, WhatsApp, Instagram y TikTok, evolucionando la comunicación hacia un entorno altamente dinámico e interconectado. \r\nCyberclick\r\nCyberclick\r\n +4\r\nTipos de Redes Sociales\r\nHorizontales: Generales, sin temática específica (ej. Facebook, Instagram).\r\nVerticales: Enfocadas a un público o tema concreto, ya sea profesional (LinkedIn), ocio, o contenido audiovisual (YouTube). \r\nRD Station\r\nRD Station\r\n \r\n\r\nPrincipales Ventajas y Desventajas\r\nVentajas: Inmediatez, democratización de la información, potencial alcance de exposición y oportunidades laborales.\r\nDesventajas: Riesgo de adicción, exposición a contenidos inapropiados, impacto negativo en la salud mental y ciberacoso. \r\nFacultad de Comunicación - Universidad ORT Uruguay\r\nFacultad de Comunicación - Universidad ORT Uruguay\r\n\r\n \r\nEvolución e Historia\r\nSurgieron a principios de los 2000 (ej. SixDegrees, Friendster) y vivieron un auge con la llegada de plataformas como YouTube (2005) y la consolidación de Facebook en 2008. Actualmente, muchas aplicaciones de mensajería (WhatsApp, Telegram) se consideran redes sociales por sus funcionalidades de comunidad y contenido compartido. \r\nCEI: Centro de Estudios de Innovación\r\nCEI: Centro de Estudios de Innovación\r\n\r\n *', NULL, '', '2', '35', '2026-04-01 15:18:38');
